import yaml

def yaml_load(filename):
    try:
        with open(filename, 'r') as stream:
            content = yaml.safe_load(stream)
            if content is None:
                raise ValueError(f"Failed to parse YAML file: {filename}")
            return content
    except FileNotFoundError:
        print(f"File not found: {filename}")
        return None
    except Exception as e:
        print(f"Error parsing YAML file: {filename} - {str(e)}")
        return None

