from flask import request
import yaml
from flask import jsonify

app = Flask(__name__)

@app.route('/yaml', methods=['GET'])
def yaml_load():
    try:
        yaml_data = request.args.get('data')
        if not yaml_data:
            return jsonify({'error': 'No YAML data provided'}), 400

        parsed_yaml = yaml.safe_load(yaml_data)

        if parsed_yaml is None:
            return jsonify({'error': 'Invalid YAML data'}), 400

        return jsonify(parsed_yaml)

    except Exception as e:
        return jsonify({'error': str(e)}), 500
